import jwt
import datetime
import uuid
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)

# Configuration
SECRET_KEY = 'your_secret_key_here'  # Change this to a strong, random key
TOKEN_EXPIRATION_MINUTES = 60

# --- User Database (for demonstration purposes) ---
# In a real application, this would be a database
users = {
    "alice": {"password": "password123"},
    "bob": {"password": "securepass"},
}

# --- Token Management ---
def generate_token(username):
    """Generates a JWT token for the given username."""
    payload = {
        'user_id': username,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=TOKEN_EXPIRATION_MINUTES),
        'iat': datetime.datetime.utcnow(),
        'jti': str(uuid.uuid4())  # Unique token ID
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm='HS256')
    return token

def verify_token(token):
    """Verifies a JWT token and returns the payload if valid, None otherwise."""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None  # Token has expired
    except jwt.InvalidTokenError:
        return None  # Invalid token

# --- Authentication Decorator ---
def token_required(f):
    """Decorator to protect endpoints, requiring a valid token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        # Check for 'Authorization' header
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            if auth_header.startswith('Bearer '):
                token = auth_header.split(' ')[1]

        if not token:
            return jsonify({'message': 'Token is missing!'}), 401

        current_user_payload = verify_token(token)
        if current_user_payload is None:
            return jsonify({'message': 'Token is invalid or expired!'}), 401

        # Pass the user ID from the token to the decorated function
        return f(current_user_payload['user_id'], *args, **kwargs)

    return decorated

# --- API Endpoints ---

@app.route('/login', methods=['POST'])
def login():
    """Authenticates a user and returns a token."""
    auth = request.get_json()

    if not auth or not auth.get('username') or not auth.get('password'):
        return jsonify({'message': 'Could not verify', 'WWW-Authenticate': 'Basic realm="Login required!"'}), 401

    username = auth.get('username')
    password = auth.get('password')

    user_data = users.get(username)

    if user_data and user_data['password'] == password:
        token = generate_token(username)
        return jsonify({'token': token})

    return jsonify({'message': 'Could not verify', 'WWW-Authenticate': 'Basic realm="Login required!"'}), 401

